__global__ void fused_conv_sub_tanh_sub_kernel(
    const scalar_t* input,
    const scalar_t* weight,
    const scalar_t* bias,
    scalar_t* output,
    const scalar_t subtract1,
    const scalar_t subtract2,
    const int batch_size,
    const int in_channels,
    const int out_channels,
    const int input_height,
    const int input_width,
    const int kernel_size,
    const int output_height,
    const int output_width,
    const int stride,
    const int padding
) {
    const int output_size = batch_size * out_channels * output_height * output_width;
    const int idx = blockIdx.x * blockDim.x + threadIdx.x;

    if (idx >= output_size) return;

    // Calculate output position
    const int n = idx / (out_channels * output_height * output_width);
    const int c = (idx / (output_height * output_width)) % out_channels;
    const int h = (idx / output_width) % output_height;
    const int w = idx % output_width;

    scalar_t value = bias ? bias[c] : static_cast<scalar_t>(0);

    // Perform convolution
    for (int ic = 0; ic < in_channels; ++ic) {
        for (int kh = 0; kh < kernel_size; ++kh) {
            for (int kw = 0; kw < kernel_size; ++kw) {
                const int ih = h * stride + kh - padding;
                const int iw = w * stride + kw - padding;

                if (ih >= 0 && ih < input_height && iw >= 0 && iw < input_width) {
                    const int input_idx = ((n * in_channels + ic) * input_height + ih) * input_width + iw;
                    const int weight_idx = ((c * in_channels + ic) * kernel_size + kh) * kernel_size + kw;

                    value += input[input_idx] * weight[weight_idx];
                }
            }
        }
    }

    // Apply subtract1 -> tanh -> subtract2
    value = value - subtract1;
    value = tanhf(value);  // Use tanhf for float, tanh for double
    value = value - subtract2;

    output[idx] = value;
}

torch::Tensor fused_conv_sub_tanh_sub_cuda(
    torch::Tensor input,
    torch::Tensor weight,
    torch::Tensor bias,
    float subtract1,
    float subtract2,
    int stride,
    int padding
) {
