#include <torch/extension.h>
#include <cuda_runtime.h>

template<typename scalar_t>
__global__ void avgpool_kernel(
    const scalar_t* input,
    scalar_t* output,
    const int batch_size,
    const int channels,
    const int input_height,
    const int input_width,
    const int kernel_size,
    const int output_height,
    const int output_width
) {
    const int output_size = batch_size * channels * output_height * output_width;
    const int idx = blockIdx.x * blockDim.x + threadIdx.x;

    if (idx >= output_size) return;

    const int n = idx / (channels * output_height * output_width);
    const int c = (idx / (output_height * output_width)) % channels;
    const int h = (idx / output_width) % output_height;
    const int w = idx % output_width;

    const int start_h = h * kernel_size;
    const int start_w = w * kernel_size;
    const int end_h = min(start_h + kernel_size, input_height);
    const int end_w = min(start_w + kernel_size, input_width);

    scalar_t sum = static_cast<scalar_t>(0);
    int count = 0;

    for (int ih = start_h; ih < end_h; ++ih) {
        for (int iw = start_w; iw < end_w; ++iw) {
            const int input_idx = ((n * channels + c) * input_height + ih) * input_width + iw;
            sum += input[input_idx];
            count++;
        }
    }

    output[idx] = sum / static_cast<scalar_t>(count);
}

torch::Tensor avgpool_cuda(
    torch::Tensor input,
    int kernel_size
) {
