    const auto channels = input.size(1);
    const auto input_height = input.size(2);
    const auto input_width = input.size(3);

    const int output_height = input_height / kernel_size;
    const int output_width = input_width / kernel_size;

    auto output = torch::empty({batch_size, channels, output_height, output_width},
                              input.options());

    const int output_size = batch_size * channels * output_height * output_width;
    const int block_size = 256;
    const int num_blocks = (output_size + block_size - 1) / block_size;

    AT_DISPATCH_FLOATING_TYPES(input.scalar_type(), "avgpool_cuda", ([&] {
        avgpool_kernel<scalar_t><<<num_blocks, block_size>>>(
            input.data_ptr<scalar_t>(),
            output.data_ptr<scalar_t>(),
            batch_size,
            channels,
            input_height,
            input_width,
            kernel_size,
            output_height,
            output_width
        );
    }));

    return output;
}
