        self.avgpool_op = avgpool_op

        # Fixed stride and padding to match nn.Conv2d default
        self.stride = 1
        self.padding = 0  # Changed from kernel_size // 2 to match original

    def forward(self, x):
        # Fused convolution + subtract + tanh + subtract
        x = self.fused_conv_activation.fused_conv_sub_tanh_sub_cuda(
            x, 
            self.weight, 
            self.bias, 
            self.subtract1_value, 
            self.subtract2_value,
            self.stride,
            self.padding
        )

        # Optimized average pooling
        x = self.avgpool_op.avgpool_cuda(x, self.kernel_size_pool)

