template<typename scalar_t>
__global__ void fused_conv_sub_tanh_sub_kernel(
    const scalar_t* input,
    const scalar_t* weight,
    const scalar_t* bias,
    scalar_t* output,
    const scalar_t subtract1,
    const scalar_t subtract2,
