    const int c = (idx / (output_height * output_width)) % channels;
    const int h = (idx / output_width) % output_height;
    const int w = idx % output_width;

    const int start_h = h * kernel_size;
    const int start_w = w * kernel_size;
    const int end_h = min(start_h + kernel_size, input_height);
    const int end_w = min(start_w + kernel_size, input_width);

